FORUM_POST_FORMAT = bytes.fromhex('3c68323e7b6865616465727d3c2f68323e3c703e7b6d6573736167657d3c2f703e7b6f7074696f6e737d').decode()

def build_forum_entry(post_title: str, post_body: str, bullet_points: list[str]):
    bytes.fromhex('').decode()
    bullet_points_html = bytes.fromhex('3c756c3e').decode() + ''.join(bullet_points) + bytes.fromhex('3c2f756c3e').decode()
    forum_post_html = FORUM_POST_FORMAT.format(header=post_title, message=post_body, options=bullet_points_html)